{"path": "~/hermes_home_setup/check_env.ps1", "content": "#!/usr/bin/env pwsh
# Hermes Windows环境检查脚本
# 运行: powershell -ExecutionPolicy Bypass -File check_env.ps1

Write-Host "=== Hermes Windows 环境检查 ===" -ForegroundColor Cyan
Write-Host "检查时间: $(Get-Date)" -ForegroundColor Gray
Write-Host ""

# 1. 检查Python
Write-Host "1. 检查Python安装..." -ForegroundColor Yellow
$pythonVersion = ""
try {
    $pythonVersion = python --version 2>&1
    Write-Host "   Python版本: $pythonVersion" -ForegroundColor Green
} catch {
    Write-Host "   ❌ Python未安装或不在PATH中" -ForegroundColor Red
}

# 2. 检查pip
Write-Host "2. 检查pip..." -ForegroundColor Yellow
try {
    $pipVersion = pip --version 2>&1
    Write-Host "   pip版本: $pipVersion" -ForegroundColor Green
} catch {
    Write-Host "   ❌ pip未安装或不在PATH中" -ForegroundColor Red
}

# 3. 检查Git（可选）
Write-Host "3. 检查Git..." -ForegroundColor Yellow
try {
    $gitVersion = git --version 2>&1
    Write-Host "   Git版本: $gitVersion" -ForegroundColor Green
} catch {
    Write-Host "   ⚠️ Git未安装（可选，用于克隆技能仓库）" -ForegroundColor Yellow
}

# 4. 检查Ollama（如果已安装）
Write-Host "4. 检查Ollama..." -ForegroundColor Yellow
$ollamaRunning = $false
try {
    $ollamaResponse = Invoke-WebRequest -Uri "http://localhost:11434/api/tags" -UseBasicParsing -TimeoutSec 3 -ErrorAction SilentlyContinue
    if ($ollamaResponse.StatusCode -eq 200) {
        $ollamaRunning = $true
        Write-Host "   ✅ Ollama服务正在运行" -ForegroundColor Green
    }
} catch {
    Write-Host "   ℹ️ Ollama未运行或不在端口11434" -ForegroundColor Gray
}

# 5. 检查网络连接
Write-Host "5. 检查网络连接..." -ForegroundColor Yellow
try {
    $testConnection = Test-Connection -ComputerName "api.deepseek.com" -Count 1 -Quiet -ErrorAction SilentlyContinue
    if ($testConnection) {
        Write-Host "   ✅ 可访问DeepSeek API" -ForegroundColor Green
    } else {
        Write-Host "   ⚠️ 无法访问DeepSeek API（可能需代理）" -ForegroundColor Yellow
    }
} catch {
    Write-Host "   ⚠️ 网络检查失败" -ForegroundColor Yellow
}

# 6. 磁盘空间检查
Write-Host "6. 检查磁盘空间..." -ForegroundColor Yellow
$drive = Get-PSDrive -Name C -ErrorAction SilentlyContinue
if ($drive) {
    $freeGB = [math]::Round($drive.Free / 1GB, 2)
    $totalGB = [math]::Round($drive.Used / 1GB + $drive.Free / 1GB, 2)
    Write-Host "   C盘可用空间: ${freeGB}GB / ${totalGB}GB" -ForegroundColor Green
    if ($freeGB -lt 10) {
        Write-Host "   ⚠️ 磁盘空间不足（建议至少10GB）" -ForegroundColor Red
    }
}

# 7. 检查防火墙设置
Write-Host "7. 检查防火墙端口..." -ForegroundColor Yellow
$portsToCheck = @(11434, 8642, 8648, 3001, 8765)
foreach ($port in $portsToCheck) {
    $listener = Get-NetTCPConnection -LocalPort $port -State Listen -ErrorAction SilentlyContinue
    if ($listener) {
        Write-Host "   ⚠️ 端口 ${port} 已被占用" -ForegroundColor Yellow
    }
}

# 8. 检查WSL状态（如安装）
Write-Host "8. 检查WSL状态..." -ForegroundColor Yellow
try {
    $wslInfo = wsl --list --verbose 2>&1
    if ($LASTEXITCODE -eq 0) {
        Write-Host "   ✅ WSL已安装" -ForegroundColor Green
        Write-Host "   $wslInfo" -ForegroundColor Gray
    } else {
        Write-Host "   ℹ️ WSL未安装（可选）" -ForegroundColor Gray
    }
} catch {
    Write-Host "   ℹ️ WSL未安装（可选）" -ForegroundColor Gray
}

Write-Host ""
Write-Host "=== 检查完成 ===" -ForegroundColor Cyan

# 总结和建议
Write-Host ""
Write-Host "📋 建议：" -ForegroundColor Cyan

if (-not $pythonVersion) {
    Write-Host "1. 请安装Python 3.8+：https://www.python.org/downloads/" -ForegroundColor Yellow
}

if (-not $ollamaRunning) {
    Write-Host "2. 建议安装Ollama（节约API费用）：" -ForegroundColor Yellow
    Write-Host "   a. 下载：https://ollama.com/download/windows" -ForegroundColor Gray
    Write-Host "   b. 运行：ollama serve" -ForegroundColor Gray
    Write-Host "   c. 拉取模型：ollama pull qwen2.5:7b" -ForegroundColor Gray
}

Write-Host "3. 根据你的选择执行安装：" -ForegroundColor Yellow
Write-Host "   - 选项A（直接安装）：运行 install_direct.ps1" -ForegroundColor Gray
Write-Host "   - 选项B（WSL安装）：参考 install_wsl.md" -ForegroundColor Gray
Write-Host "   - 选项C（简化架构）：运行 setup_simple_server.py" -ForegroundColor Gray

Write-Host ""
Write-Host "💡 安装完成后，可以运行：hermes web --port 8658 启动Web界面" -ForegroundColor Green"}

{"path": "~/hermes_home_setup/simple_ollama_server.py", "content": "#!/usr/bin/env python3
"""
简化架构的家庭Hermes服务器（方案C）
仅运行Ollama服务并提供简单的HTTP API供笔记本调用
这样笔记本上的Hermes可以远程使用家庭电脑的Ollama模型，节约API费用
"""

import os
import sys
import json
import time
import threading
import subprocess
from datetime import datetime
from pathlib import Path

# 第三方库依赖
try:
    import requests
    from flask import Flask, request, jsonify
    from flask_cors import CORS
except ImportError:
    print("❌ 缺少依赖库，请先安装：")
    print("   pip install flask flask-cors requests")
    sys.exit(1)

# 配置
HOST = "0.0.0.0"  # 监听所有网络接口
PORT = 8765       # 服务端口
OLLAMA_URL = "http://localhost:11434"  # Ollama服务地址
MODEL = "qwen2.5:7b"  # 默认模型
LOG_DIR = Path.home() / ".hermes_home" / "logs"
LOG_DIR.mkdir(parents=True, exist_ok=True)

# 创建Flask应用
app = Flask(__name__)
CORS(app)  # 允许跨域请求

def log_message(level, message):
    """记录日志到文件和控制台"""
    timestamp = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
    log_entry = f"[{timestamp}] [{level}] {message}"

    # 控制台输出
    print(log_entry)

    # 文件日志
    log_file = LOG_DIR / f"server_{datetime.now().strftime('%Y%m%d')}.log"
    with open(log_file, "a", encoding="utf-8") as f:
        f.write(log_entry + "\n")

def check_ollama_connection():
    """检查Ollama服务是否可用"""
    try:
        response = requests.get(f"{OLLAMA_URL}/api/tags", timeout=5)
        if response.status_code == 200:
            models = response.json().get("models", [])
            model_names = [m.get("name", "") for m in models]
            log_message("INFO", f"Ollama服务正常，可用模型: {', '.join(model_names)}")
            return True, model_names
    except Exception as e:
        log_message("ERROR", f"无法连接Ollama: {e}")
    return False, []

def generate_with_ollama(prompt, model=None, temperature=0.7, max_tokens=1024):
    """调用Ollama生成文本"""
    if model is None:
        model = MODEL

    url = f"{OLLAMA_URL}/api/generate"
    payload = {
        "model": model,
        "prompt": prompt,
        "stream": False,
        "options": {
            "temperature": temperature,
            "num_predict": max_tokens
        }
    }

    try:
        log_message("INFO", f"调用Ollama模型: {model}, 提示长度: {len(prompt)}")
        start_time = time.time()

        response = requests.post(url, json=payload, timeout=60)
        response.raise_for_status()

        result = response.json()
        elapsed = time.time() - start_time

        log_message("INFO", f"生成完成，耗时: {elapsed:.2f}秒，token数: {result.get('total_duration', 0)}")

        return {
            "success": True,
            "text": result.get("response", ""),
            "model": model,
            "tokens": result.get("total_duration", 0),
            "elapsed": elapsed
        }
    except Exception as e:
        log_message("ERROR", f"Ollama生成失败: {e}")
        return {
            "success": False,
            "error": str(e),
            "model": model
        }

def process_file_content(file_path, task_type="summary"):
    """处理文件内容（简单示例）"""
    try:
        path = Path(file_path)
        if not path.exists():
            return f"❌ 文件不存在: {file_path}"

        # 根据文件类型处理
        if path.suffix.lower() in ['.txt', '.md', '.py', '.json', '.yaml', '.yml']:
            content = path.read_text(encoding='utf-8')
            if task_type == "summary":
                prompt = f"请总结以下内容，用中文简洁描述：\n\n{content[:2000]}"
            elif task_type == "keywords":
                prompt = f"提取以下内容的关键词（最多10个）：\n\n{content[:2000]}"
            else:
                prompt = f"分析以下内容：\n\n{content[:2000]}"

            return prompt
        else:
            return f"⚠️ 暂不支持的文件类型: {path.suffix}"
    except Exception as e:
        return f"❌ 处理文件失败: {e}"

# API路由
@app.route('/')
def index():
    """首页"""
    ollama_ok, models = check_ollama_connection()
    return jsonify({
        "service": "Hermes Home Assistant (Simple Server)",
        "status": "running",
        "ollama_available": ollama_ok,
        "available_models": models,
        "timestamp": datetime.now().isoformat(),
        "endpoints": {
            "/generate": "POST - 文本生成",
            "/models": "GET - 获取可用模型",
            "/health": "GET - 健康检查",
            "/process": "POST - 处理任务"
        }
    })

@app.route('/health')
def health():
    """健康检查"""
    ollama_ok, models = check_ollama_connection()
    return jsonify({
        "status": "healthy" if ollama_ok else "degraded",
        "ollama": "available" if ollama_ok else "unavailable",
        "models": models,
        "timestamp": datetime.now().isoformat()
    })

@app.route('/models')
def get_models():
    """获取可用模型列表"""
    try:
        response = requests.get(f"{OLLAMA_URL}/api/tags", timeout=5)
        if response.status_code == 200:
            models_data = response.json().get("models", [])
            return jsonify({"models": models_data})
    except Exception as e:
        return jsonify({"error": str(e)}), 500
    return jsonify({"models": []})

@app.route('/generate', methods=['POST'])
def generate_text():
    """文本生成接口"""
    data = request.json
    if not data or 'prompt' not in data:
        return jsonify({"error": "缺少prompt参数"}), 400

    prompt = data['prompt']
    model = data.get('model', MODEL)
    temperature = data.get('temperature', 0.7)
    max_tokens = data.get('max_tokens', 1024)

    result = generate_with_ollama(prompt, model, temperature, max_tokens)
    return jsonify(result)

@app.route('/process', methods=['POST'])
def process_task():
    """处理任务接口（支持文件处理）"""
    data = request.json
    if not data or 'task' not in data:
        return jsonify({"error": "缺少task参数"}), 400

    task_type = data['task']

    if task_type == "file_analysis":
        if 'file_path' not in data:
            return jsonify({"error": "缺少file_path参数"}), 400

        file_path = data['file_path']
        analysis_type = data.get('analysis_type', 'summary')

        # 处理文件内容
        prompt = process_file_content(file_path, analysis_type)
        if prompt.startswith("❌") or prompt.startswith("⚠️"):
            return jsonify({"error": prompt})

        # 调用Ollama分析
        result = generate_with_ollama(prompt)
        return jsonify({
            "task": task_type,
            "file_path": file_path,
            "analysis_type": analysis_type,
            "result": result
        })

    elif task_type == "batch_generate":
        if 'prompts' not in data:
            return jsonify({"error": "缺少prompts参数"}), 400

        prompts = data['prompts']
        model = data.get('model', MODEL)
        results = []

        for i, prompt in enumerate(prompts):
            log_message("INFO", f"批量生成 {i+1}/{len(prompts)}: {prompt[:50]}...")
            result = generate_with_ollama(prompt, model)
            results.append({
                "index": i,
                "prompt_preview": prompt[:100],
                "result": result
            })

        return jsonify({
            "task": task_type,
            "total": len(prompts),
            "results": results
        })

    else:
        return jsonify({"error": f"不支持的任务类型: {task_type}"}), 400

def start_ollama_monitor():
    """监控Ollama服务的线程"""
    def monitor():
        while True:
            ollama_ok, models = check_ollama_connection()
            if not ollama_ok:
                log_message("WARNING", "Ollama服务不可用，请检查是否运行: ollama serve")
            time.sleep(60)  # 每分钟检查一次

    thread = threading.Thread(target=monitor, daemon=True)
    thread.start()
    return thread

if __name__ == '__main__':
    log_message("INFO", f"启动简化Hermes服务器，端口: {PORT}")
    log_message("INFO", f"Ollama服务地址: {OLLAMA_URL}")

    # 检查Ollama
    ollama_ok, models = check_ollama_connection()
    if not ollama_ok:
        log_message("WARNING", "⚠️ Ollama服务未运行，请先启动: ollama serve")
        log_message("INFO", "服务仍会启动，但无法处理生成请求")

    # 启动监控线程
    monitor_thread = start_ollama_monitor()

    # 显示启动信息
    print("=" * 60)
    print("🏠 家庭Hermes简化服务器已启动")
    print(f"📡 监听地址: http://{HOST}:{PORT}")
    print(f"🤖 Ollama状态: {'✅ 正常' if ollama_ok else '❌ 未连接'}")
    if ollama_ok and models:
        print(f"📦 可用模型: {', '.join(models)}")
    print("")
    print("📋 API端点:")
    print(f"  GET  /          - 服务信息")
    print(f"  GET  /health    - 健康检查")
    print(f"  GET  /models    - 获取模型列表")
    print(f"  POST /generate  - 文本生成")
    print(f"  POST /process   - 处理任务")
    print("")
    print("💡 笔记本上调用示例:")
    print(f"  curl -X POST http://你的IP:{PORT}/generate \\")
    print('       -H "Content-Type: application/json" \\')
    print('       -d \'{"prompt":"你好", "model":"qwen2.5:7b"}\'')
    print("=" * 60)

    # 启动Flask服务
    try:
        app.run(host=HOST, port=PORT, debug=False)
    except KeyboardInterrupt:
        log_message("INFO", "服务器已停止")
    except Exception as e:
        log_message("ERROR", f"服务器启动失败: {e}")"}
